@page "/board"
@using sv_ced41ecd638f4f728630a496079bada1
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    @* Summary stats bar *@
    <div class="row g-2 mb-3">
        <div class="col">
            <div class="card text-center">
                <div class="card-body py-2">
                    <div class="fw-bold">Total</div>
                    <div class="fs-5">@allTasks.Count</div>
                </div>
            </div>
        </div>
        @foreach (var col in Columns)
        {
            <div class="col">
                <div class="card text-center">
                    <div class="card-body py-2">
                        <div class="fw-bold">@col</div>
                        <div class="fs-5">@GetTasksForColumn(col).Count</div>
                    </div>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center border-danger">
                <div class="card-body py-2">
                    <div class="fw-bold text-danger">Overdue</div>
                    <div class="fs-5 text-danger">@FilteredTasks.Count(t => t.DueDate < DateTime.Today)</div>
                </div>
            </div>
        </div>
    </div>

    @* Search bar *@
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchText" @bind:event="oninput" />
    </div>

    @* Kanban columns *@
    <div class="row g-3">
        @for (int i = 0; i < Columns.Length; i++)
        {
            var colIndex = i;
            var colName = Columns[colIndex];
            var colTasks = GetFilteredTasksForColumn(colName);

            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@colName</strong>
                        <span class="badge bg-secondary">@colTasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2" style="min-height: 200px;">
                        @foreach (var task in colTasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <div class="fw-semibold mb-1">@task.Title</div>
                                    <div class="text-muted small mb-1">@task.Assignee</div>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                        <span class="text-muted small">@task.DueDate.ToString("MMM dd")</span>
                                    </div>
                                    <div class="d-flex justify-content-between mt-1">
                                        @if (colIndex > 0)
                                        {
                                            var leftStatus = Columns[colIndex - 1];
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@movingTaskId.HasValue"
                                                    @onclick="() => MoveTaskAsync(task.Id, leftStatus)">
                                                &larr; Move Left
                                            </button>
                                        }
                                        else
                                        {
                                            <span></span>
                                        }
                                        @if (colIndex < Columns.Length - 1)
                                        {
                                            var rightStatus = Columns[colIndex + 1];
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@movingTaskId.HasValue"
                                                    @onclick="() => MoveTaskAsync(task.Id, rightStatus)">
                                                Move Right &rarr;
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @* Add task form *@
                        @if (addingToColumn == colName)
                        {
                            <div class="card border-primary mt-auto">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-2"
                                           placeholder="Title" @bind="newTitle" />
                                    <input type="text" class="form-control form-control-sm mb-2"
                                           placeholder="Assignee" @bind="newAssignee" />
                                    <select class="form-select form-select-sm mb-2" @bind="newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-2"
                                           @bind="newDueDate" />
                                    @if (addError is not null)
                                    {
                                        <div class="text-danger small mb-1">@addError</div>
                                    }
                                    <div class="d-flex gap-2">
                                        <button class="btn btn-primary btn-sm" disabled="@isSaving"
                                                @onclick="SaveNewTaskAsync">
                                            @(isSaving ? "Saving..." : "Save")
                                        </button>
                                        <button class="btn btn-outline-secondary btn-sm"
                                                disabled="@isSaving" @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    @if (addingToColumn != colName)
                    {
                        <div class="card-footer">
                            <button class="btn btn-outline-primary btn-sm w-100"
                                    @onclick="() => StartAdd(colName)">+ Add Task</button>
                        </div>
                    }
                </div>
            </div>
        }
    </div>
}

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private string? errorMessage;
    private string searchText = string.Empty;

    // Move state
    private int? movingTaskId;

    // Add task state
    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? addError;

    private List<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchText)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> GetTasksForColumn(string status) =>
        allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForColumn(string status) =>
        FilteredTasks.Where(t => t.Status == status).ToList();

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        movingTaskId = taskId;

        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private void StartAdd(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today.AddDays(7);
        addError = null;
    }

    private void CancelAdd()
    {
        addingToColumn = null;
        addError = null;
    }

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(newTitle))
        {
            addError = "Title is required.";
            return;
        }

        isSaving = true;
        addError = null;

        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle.Trim(), newAssignee.Trim(), newPriority, newDueDate);
            // CreateTaskAsync returns with default status; override to match the target column
            allTasks.Add(created with { Status = addingToColumn! });

            if (created.Status != addingToColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, addingToColumn!);
            }

            addingToColumn = null;
        }
        catch (Exception ex)
        {
            addError = ex.Message;
        }
        finally
        {
            isSaving = false;
        }
    }
}

