@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private string? errorMessage;
    private string searchText = string.Empty;

    // Move state
    private int? movingTaskId;

    // Add task state
    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? addError;

    private List<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchText)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> GetTasksForColumn(string status) =>
        allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForColumn(string status) =>
        FilteredTasks.Where(t => t.Status == status).ToList();

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        movingTaskId = taskId;

        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private void StartAdd(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today.AddDays(7);
        addError = null;
    }

    private void CancelAdd()
    {
        addingToColumn = null;
        addError = null;
    }

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(newTitle))
        {
            addError = "Title is required.";
            return;
        }

        isSaving = true;
        addError = null;

        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle.Trim(), newAssignee.Trim(), newPriority, newDueDate);
            // CreateTaskAsync returns with default status; override to match the target column
            allTasks.Add(created with { Status = addingToColumn! });

            if (created.Status != addingToColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, addingToColumn!);
            }

            addingToColumn = null;
        }
        catch (Exception ex)
        {
            addError = ex.Message;
        }
        finally
        {
            isSaving = false;
        }
    }
}
"}

